#!/usr/bin/env node
'use strict';

/**
 * OPTIONAL ship build — concatenate a game's <script src> chain into one file per
 * surface, so the APK payload loads a single file instead of ~12 requests.
 *
 * Usage: node scripts/bundle.js <id>
 * Output: games/<id>/dist/<surface>.bundle.js  (screen / lobby / controller)
 *
 * Dev/testing uses the unbundled <script> tags directly — this is not required for
 * the game to work, and runtime FPS is identical either way (file count is a load-
 * time concern only). Minification is intentionally left out (no extra deps); add a
 * minifier here later if you want smaller files.
 */
const fs = require('fs');
const path = require('path');

const id = (process.argv[2] || '').trim();
if (!id) { console.error('Usage: node scripts/bundle.js <id>'); process.exit(1); }

const root = path.join(__dirname, '..');
const gameDir = path.join(root, 'games', id);
if (!fs.existsSync(gameDir)) { console.error(`games/${id} not found.`); process.exit(1); }

const surfaces = ['screen', 'lobby', 'controller'];
const distDir = path.join(gameDir, 'dist');
fs.mkdirSync(distDir, { recursive: true });

const SRC_RE = /<script\s+src="([^"]+)"><\/script>/g;
let made = 0;

for (const surface of surfaces) {
  const htmlPath = path.join(gameDir, `${surface}.html`);
  if (!fs.existsSync(htmlPath)) continue;
  const html = fs.readFileSync(htmlPath, 'utf8');

  const parts = [];
  let m;
  while ((m = SRC_RE.exec(html)) !== null) {
    const rel = m[1].replace(/^\//, '');           // /framework/x.js -> framework/x.js
    const file = path.join(root, rel);
    if (!fs.existsSync(file)) { console.warn(`  skip (missing): ${m[1]}`); continue; }
    parts.push(`/* ===== ${m[1]} ===== */\n` + fs.readFileSync(file, 'utf8'));
  }
  SRC_RE.lastIndex = 0;

  if (!parts.length) continue;
  const out = path.join(distDir, `${surface}.bundle.js`);
  fs.writeFileSync(out, `/* Bundled for ${id}/${surface} — generated by scripts/bundle.js. Do not edit. */\n` + parts.join('\n\n'));
  console.log(`  wrote games/${id}/dist/${surface}.bundle.js (${parts.length} files)`);
  made++;
}

if (!made) { console.error('Nothing bundled — no surface HTML with <script src> tags found.'); process.exit(1); }
console.log(`Done. Replace the <script src> chain in each HTML with one tag, e.g.:`);
console.log(`  <script src="/games/${id}/dist/screen.bundle.js"></script>`);
